SELECT COUNT(alert_id) AS total_high_priority_alerts
FROM object_alerts
WHERE status = 'active' AND priority = 'high';

SELECT maintenance_type, next_maintenance_due
FROM object_maintenance
WHERE object_id = 1 AND timestamp = '2023-01-01 10:00:00';

SELECT timestamp, alert_message
FROM object_alerts
WHERE status = 'active';

SELECT SUM(cost) AS total_maintenance_cost
FROM object_maintenance
WHERE user_id = 0;

SELECT COUNT(*) 
FROM object_maintenance 
WHERE object_id = 1;

SELECT type_name, max_size
FROM object_types
ORDER BY max_size DESC;

SELECT COUNT(object_id) 
FROM object_locations 
WHERE location_id = 1;

SELECT DISTINCT o.object_name
FROM objects o
JOIN object_alerts a ON o.object_id = a.object_id;

SELECT o.object_name, o.description, o.status, o.last_known_timestamp, o.last_known_location_id
FROM objects o
JOIN object_maintenance om ON o.object_id = om.object_id;
